module piso_shift_register(
	input clk,
	input reset_n,
	input load,
	input [7:0] data_in,
	output reg data_out);

reg [7:0] obf_shift_reg;

always @(posedge clk)
	if (!reset_n)
		obf_shift_reg <= 0;
	else if (load)
		obf_shift_reg <= data_in;
	else
		obf_shift_reg <= {obf_shift_reg[6:0], 1'b0};

always @(obf_shift_reg)
	data_out = obf_shift_reg[7];

endmodule
